mapper.select:
WITH RECURSIVE CTE AS (SELECT 0 AS LEVEL, 0 AS AP_NO, G.INSA_CODE, G.TEAM_NAME, G.TEAM_NAME AS FULL_TEAM_NM, CAST('pc' AS VARCHAR(50)) AS PARENT, '' AS CONNECTED FROM pi_group G WHERE G.INSA_CODE IN (SELECT INSA_CODE FROM pi_target_service WHERE USER_NO = #{user_no} AND ENABLE = 'Y') UNION ALL SELECT CTE.LEVEL + 1 AS LEVEL, 0 AS AP_NO, PG.INSA_CODE, PG.TEAM_NAME, CONCAT(CTE.FULL_TEAM_NM, '>', PG.TEAM_NAME) AS FULL_TEAM_NM, PG.UP_IDX AS PARENT, PG.UP_IDX AS CONNECTED FROM pi_group PG, CTE WHERE PG.UP_IDX = CTE.INSA_CODE ) SELECT CTE.INSA_CODE AS IDX, CTE.AP_NO, '' AS FULL_NAME, '' AS HOST_NAME, CTE.TEAM_NAME AS NAME, '' AS SERIAL, '' AS PLATFORM, CTE.PARENT AS UP_IDX, CAST('' AS VARCHAR(500)) AS TARGET_ID, CAST('' AS VARCHAR(500)) AS LOCATION_ID, 0 AS CONNECTED, 0 AS TYPE, '' AS AGENT_CONNECTED, 0 AS AGENT_CONNECTED_CHK, '' AS AGENT_CONNECTED_IP FROM CTE GROUP BY CTE.INSA_CODE UNION ALL SELECT USERS.* FROM (SELECT U.USER_NO AS IDX, 0 AS AP_NO, '' AS FULL_NAME, '' AS HOST_NAME, CONCAT(U.USER_NAME,' (',IFNULL(COUNT(T.TARGET_ID),'0'),')') AS NAME, '' AS SERIAL, '' AS PLATFORM, U.INSA_CODE AS UP_IDX, CAST('' AS VARCHAR(500)) AS TARGET_ID, CAST('' AS VARCHAR(500)) AS LOCATION_ID, IFNULL(COUNT(T.TARGET_ID), 0) AS CONNECTED, 2 AS TYPE, '' AS AGENT_CONNECTED, 0 AS AGENT_CONNECTED_CHK, '' AS AGENT_CONNECTED_IP FROM CTE, pi_user U LEFT OUTER JOIN pi_target_user TU ON U.USER_NO = TU.USER_NO LEFT OUTER JOIN pi_targets T ON TU.TARGET_ID = T.TARGET_ID AND T.TARGET_USE = 'Y' LEFT OUTER JOIN PI_AP_SERVER AP ON (TU.AP_NO IS NULL OR TU.AP_NO = AP.AP_NO) WHERE U.INSA_CODE = CTE.INSA_CODE AND DATE_FORMAT(U.ENDDATE, '%Y-%m-%d') >= DATE_FORMAT(NOW(), '%Y-%m-%d') AND AP.IS_SERVER != 1
AND U.USER_NO != #{user_no}
AND ACC_YN ='Y' GROUP BY U.USER_NAME, U.USER_NO ) USERS UNION ALL (SELECT D.* FROM (SELECT T.TARGET_ID AS IDX, T.AP_NO, T.NAME AS FULL_NAME, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, (CASE WHEN L.PROTOCOL = 'onedrive' THEN L.PATH ELSE SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) END) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.PLATFORM, (CASE WHEN L.PROTOCOL = 'onedrive' THEN L.PROTOCOL WHEN TU.USER_NO IS NOT NULL THEN TU.USER_NO ELSE 'noGroupPC' END) AS UP_IDX, T.TARGET_ID, L.LOCATION_ID, 0 AS CONNECTED, 1 AS TYPE, (CASE WHEN A.AGENT_CONNECTED = 1 THEN 1 ELSE 0 END) AS AGENT_CONNECTED, IF(T.TYPE = 1, '1', '0') AS AGENT_CONNECTED_CHK, IFNULL(A.AGENT_CONNECTED_IP,'') AS AGENT_CONNECTED_IP FROM CTE, pi_user U, pi_target_user TU, pi_ap_server AP, pi_targets T LEFT OUTER JOIN PI_AGENTS A ON A.AP_NO = T.AP_NO AND A.AGENT_NAME = T.NAME LEFT OUTER JOIN PI_LOCATIONS L ON T.TARGET_ID = L.TARGET_ID AND (L.DESCRIPTION REGEXP 'Catalog|All local files|OneDrive') WHERE 1 = 1 AND T.TARGET_ID = TU.TARGET_ID AND T.AP_NO = TU.AP_NO AND T.AP_NO = AP.AP_NO AND U.USER_NO = TU.USER_NO AND AP.IS_SERVER != 1 AND U.INSA_CODE = CTE.INSA_CODE AND U.ACC_YN ='Y' ORDER BY NAME) AS D GROUP BY D.NAME, D.TARGET_ID, D.LOCATION_ID)

mapper.update:
UPDATE pi_server_group
SET UP_IDX= #{up_idx}
WHERE IDX = #{idx};

UPDATE PI_SERVER_GROUP 
SET NAME = #{name}
WHERE 1 = 1
  AND IDX = #{idx}

