mapper.select:
WITH RECURSIVE CTE AS (SELECT 0 AS LEVEL, 0 AS AP_NO, G.INSA_CODE, G.TEAM_NAME, G.TEAM_NAME AS FULL_TEAM_NM, CAST('pc' AS VARCHAR(50)) AS PARENT, '' AS CONNECTED FROM pi_group G WHERE G.INSA_CODE IN (SELECT INSA_CODE FROM pi_target_service WHERE USER_NO = '${user_no}' AND ENABLE = 'Y') UNION ALL SELECT CTE.LEVEL + 1 AS LEVEL, 0 AS AP_NO, PG.INSA_CODE, PG.TEAM_NAME, CONCAT(CTE.FULL_TEAM_NM, '>', PG.TEAM_NAME) AS FULL_TEAM_NM, PG.UP_IDX AS PARENT, PG.UP_IDX AS CONNECTED FROM pi_group PG, CTE WHERE PG.UP_IDX = CTE.INSA_CODE ) SELECT CTE.* FROM CTE GROUP BY CTE.INSA_CODE UNION ALL SELECT 99 AS LEVEL, D.AP_NO, D.IDX, D.NAME, '', D.UP_IDX AS PARENT, D.CONNECTED FROM (SELECT U.USER_NO AS IDX, TU.AP_NO, CONCAT(U.USER_NAME,' (',IFNULL(COUNT(T.TARGET_ID),'0'),')') AS NAME, U.INSA_CODE AS UP_IDX, 1 AS TYPE, IFNULL(COUNT(T.TARGET_ID), '') AS CONNECTED FROM CTE, pi_user U LEFT OUTER JOIN pi_target_user TU ON U.USER_NO = TU.USER_NO LEFT OUTER JOIN pi_targets T ON TU.TARGET_ID = T.TARGET_ID AND T.TARGET_USE = 'Y' LEFT OUTER JOIN PI_AP_SERVER AP ON (TU.AP_NO IS NULL OR TU.AP_NO = AP.AP_NO) WHERE U.INSA_CODE = CTE.INSA_CODE AND DATE_FORMAT(U.ENDDATE, '%Y-%m-%d') >= DATE_FORMAT(NOW(), '%Y-%m-%d') AND AP.IS_SERVER != 1
AND U.USER_NO != #{user_no}
AND ACC_YN ='Y' GROUP BY U.USER_NAME, U.USER_NO ) D
